```javascript
const express = require('express');
const app = express();
const port = 3000;

class SelectionStrategy {
    select(filteredItems, usageCounts) {
        throw new Error("This method should be overridden!");
    }
}

class LeastUsedStrategy extends SelectionStrategy {
    select(filteredItems, usageCounts) {
        const leastUsed = Math.min(...filteredItems.map(item => usageCounts[item]));
        const candidates = filteredItems.filter(item => usageCounts[item] === leastUsed);
        return candidates[Math.floor(Math.random() * candidates.length)];
    }
}

class RandomStrategy extends SelectionStrategy {
    select(filteredItems) {
        return filteredItems[Math.floor(Math.random() * filteredItems.length)];
    }
}

class MostPopularStrategy extends SelectionStrategy {
    select(filteredItems, usageCounts) {
        const mostPopular = Math.max(...filteredItems.map(item => usageCounts[item]));
        const candidates = filteredItems.filter(item => usageCounts[item] === mostPopular);
        return candidates[Math.floor(Math.random() * candidates.length)];
    }
}

class Balancer {
    constructor(items) {
        this.items = items;
        this.usageCounts = {};
        this.items.forEach(item => this.usageCounts[item] = 0);
        this.history = [];
    }

    select(filterFn, strategy) {
        const filteredItems = this.items.filter(filterFn);
        if (filteredItems.length === 0) {
            throw new Error("No items available for selection.");
        }

        const selectedItem = strategy.select(filteredItems, this.usageCounts);
        this.usageCounts[selectedItem]++;
        this.history.push(selectedItem);
        return selectedItem;
    }

    getSelectionHistory() {
        return this.history.slice();
    }

    getUsageCounts() {
        return { ...this.usageCounts };
    }
}

// Example API endpoint for selection
app.get('/select', (req, res) => {
    const items = ['item1', 'item2', 'item3', 'item4', 'item5'];
    const balancer = new Balancer(items);
    const leastUsedStrategy = new LeastUsedStrategy();

    try {
        const selectedItem = balancer.select(item => true, leastUsedStrategy); // No filter
        res.json({
            selected: selectedItem,
            history: balancer.getSelectionHistory(),
            usageCounts: balancer.getUsageCounts()
        });
    } catch (error) {
        console.error("Selection Error:", error.message);
        res.status(500).send("An error occurred during item selection.");
    }
});

app.listen(port, () => {
    console.log(`Balancer API running at http://localhost:${port}/select`);
});
```

