    arView.addGestureRecognizer(longPressGesture)

    // Add pinch gesture for scaling
    let pinchGesture = UIPinchGestureRecognizer(target: self, action: #selector(handlePinch(_:)))
    arView.addGestureRecognizer(pinchGesture)
}

@objc func handleLongPress(_ gesture: UILongPressGestureRecognizer) {
    if gesture.state == .began {
        let location = gesture.location(in: arView)
        let hitTestResults = arView.hitTest(location, types: .featurePoint)

        if let hitTestResult = hitTestResults.first {
            let sphereNode = createSphereNode()
            let position = SCNVector3(hitTestResult.worldTransform.columns.3.x,
                                       hitTestResult.worldTransform.columns.3.y,
                                       hitTestResult.worldTransform.columns.3.z)
            sphereNode.position = position
            arView.scene.rootNode.addChildNode(sphereNode)
        }
    }
}

@objc func handleTap(_ gesture: UITapGestureRecognizer) {
    let location = gesture.location(in: arView)
    let hitTestResults = arView.hitTest(location, options: nil)

    if let hitTestResult = hitTestResults.first, let node = hitTestResult.node as? SCNNode {
        SCNTransaction.begin()
        SCNTransaction.animationDuration = 0.2
        node.scale = SCNVector3(1.2, 1.2, 1.2)
        SCNTransaction.commit()
        node.geometry?.firstMaterial?.diffuse.contents = UIColor.random()
    }
}

@objc func handlePinch(_ gesture: UIPinchGestureRecognizer) {
    guard let selectedNode = currentlySelectedNode else { return }
    if gesture.state == .changed {
        let scale = gesture.scale
        selectedNode.scale = SCNVector3(scale, scale, scale)
        gesture.scale = 1.0
    }
}

func createSphereNode() -> SCNNode {
    let geometry = SCNSphere(radius: 0.1)
    let material = SCNMaterial()
    material.diffuse.contents = UIColor.random()
    geometry.materials = [material]

