}

func createCubeNode() -> SCNNode {
    let geometry = SCNBox(width: 0.1, height: 0.1, length: 0.1, chamferRadius: 0)
    let material = SCNMaterial()
    material.diffuse.contents = UIColor.random()
    geometry.materials = [material]

    let cubeNode = SCNNode(geometry: geometry)
    cubeNode.physicsBody = SCNPhysicsBody(type: .dynamic, shape: nil) // Enable physics

    return cubeNode
}

// Example UI setup for shape selection
func setupShapeSelectionButtons() {
    let sphereButton = UIButton(frame: CGRect(x: 20, y: 50, width: 100, height: 50))
    sphereButton.setTitle("Sphere", for: .normal)
