var currentShape: ShapeType = .sphere // Enum to define selected shape

enum ShapeType {
    case sphere
    case cube
    // Additional shapes can be added here
}

// Long press gesture recognizer to add objects
@objc func handleLongPress(_ gesture: UILongPressGestureRecognizer) {
    if gesture.state == .began {
        let location = gesture.location(in: arView)
        let hitTestResults = arView.hitTest(location, types: .featurePoint)

        if let hitTestResult = hitTestResults.first {
            let node: SCNNode
            switch currentShape {
            case .sphere:
                node = createSphereNode()
            case .cube:
                node = createCubeNode()
            }
            let position = SCNVector3(hitTestResult.worldTransform.columns.3.x,
                                       hitTestResult.worldTransform.columns.3.y,
                                       hitTestResult.worldTransform.columns.3.z)
            node.position = position
            arView.scene.rootNode.addChildNode(node)
        }
    }
}

// Function to create a cube node
